INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f551624a-31bc-4897-a033-7c0c8f33192c$tag$, $tag$2026012100111$tag$, $tag$Sérgio Matias (5583987807806)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"21/01/2026 11:36:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Boa tarde, Thaianne.","time":"21/01/2026 12:18:49"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu interesse pelo nosso curso de Graduação em Direito  e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\n\nPodemos conversar agora?","time":"21/01/2026 13:25:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* Posso lhe enviar as informações sobre o curso?","time":"22/01/2026 08:30:44","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Boa tarde","time":"22/01/2026 12:08:20"},{"role":"client","text":"Tenho interesse, mas deixa eu explicar meu caso…","time":"22/01/2026 12:08:28"},{"role":"client","text":"Há alguns anos abandonei o curso, retornei há 2 anos atrás e não dei continuidade. Agora pretendo voltar e gostaria de saber como proceder","time":"22/01/2026 12:09:46"},{"role":"client","text":"Parei no 9 período e ficaram algumas pendentes","time":"22/01/2026 12:10:20"},{"role":"agent","text":"*Thayanne Sales:* Me envia seu nome completo, para verificar ","time":"22/01/2026 13:25:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Não foi com vocês, foi em outra faculdade","time":"22/01/2026 13:26:27"},{"role":"agent","text":"*Thayanne Sales:* Entendi","time":"22/01/2026 13:27:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:*  📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"22/01/2026 13:27:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Você solicita esses documento a instituição que você fez, que envia por e-mail e a direção irá analisar ","time":"22/01/2026 13:28:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok","time":"22/01/2026 13:28:29"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"22/01/2026 13:30:17","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Por enquanto só isso mesmo","time":"22/01/2026 13:30:35"},{"role":"client","text":"Agradeço!","time":"22/01/2026 13:30:38"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"22/01/2026 13:33:31","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nSérgio Matias, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"22/01/2026 13:33:35"}]$tag$, $tag$2026-01-21 11:36:34+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 9, 2, 9, 9, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c2349387-080e-4901-bb11-b4b1ffdab56f$tag$, $tag$2026012100117$tag$, $tag$Deoclécio Vieira de Melo Neto (5583993620276)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"21/01/2026 12:01:26"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"21/01/2026 12:01:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"21/01/2026 13:33:12"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"21/01/2026 13:33:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"21/01/2026 13:33:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"21/01/2026 13:33:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"21/01/2026 13:33:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"21/01/2026 13:33:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Olá, há algum benefício para quem é membro da Cidade Viva, lider de ministério/conexão?","time":"21/01/2026 14:00:30"},{"role":"agent","text":"*Thayanne Sales:* Vou verificar. Momento","time":"21/01/2026 14:03:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"ok","time":"21/01/2026 14:08:44"},{"role":"agent","text":"*Thayanne Sales:* Boa noticia foi liberado mais 10%, totalizando 30% e as mensalidades ficam de R$ 279,79","time":"21/01/2026 14:31:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Usando o cupom: BOLSA30","time":"21/01/2026 14:32:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"tá ótimo","time":"21/01/2026 14:36:09"},{"role":"client","text":"Devo usar essa cupom já na matrícula?","time":"21/01/2026 14:40:32"},{"role":"agent","text":"*Thayanne Sales:* sim","time":"21/01/2026 14:40:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69710fad857cefe80a080b61)","time":"21/01/2026 14:41:01"},{"role":"client","text":"Está informando &quot;cupom inválido&quot;","time":"21/01/2026 14:41:29"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69710fda857cefe80a080b86)","time":"21/01/2026 14:41:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Permanece o mesmo erro, mesmo depois de ter reiniciado o formulário. Tenho outras dúvidas quanto aos documentos. Vou digitar abaixo","time":"21/01/2026 14:44:57"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/697110c8e2baebf3d20e7b84)","time":"21/01/2026 14:45:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/697110d59bc81b2c20077890)","time":"21/01/2026 14:45:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Estou fazendo a matrícula como graduado. Há alguns documentos pra fazer upload.\n*Histórico escolar expedido pela instituição de origem* e *Ementas das disciplinas cursadas, em caso de aproveitamento de disciplinas* esses documento é apenas para o caso de transferência de instituição ou devo colocar também. Não tenho as ementas do meu curso de graduação, terei que conseguir na universidade.\n*Histórico escolar completo do ensino médio* - creio que não tenho mais esse documento, pois faz muitos anos que conclui (risos)\nDemais documentos estão OK","time":"21/01/2026 14:49:14"},{"role":"client","text":"Eu finalizei a inscrição sem colocar os documentos acima. Caso seja necessário, apresento posteriormente","time":"21/01/2026 15:04:38"},{"role":"client","text":"mas, não apareceu a tela para impressão do boleto de pagamento","time":"21/01/2026 15:04:49"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69711c3771069291a80cf430)","time":"21/01/2026 15:34:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Deoclecio Vieira de Melo Neto","time":"21/01/2026 15:40:27"},{"role":"client","text":"977.564.154-34","time":"21/01/2026 15:40:30"},{"role":"agent","text":"*Thayanne Sales:* Pronto, foi liberado o seu contrato Agora é só ir no mesmo link que fez a inscrição, na parte \" já me inscrevi\", colocar o seu CPF e na senha é sua data de nascimento completo.\nIr em \"Visualização de contrato\", da o aceite e após isso vai abrir a forma de pagamento. ","time":"21/01/2026 17:23:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde!","time":"22/01/2026 13:31:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Deu certo?","time":"22/01/2026 13:31:22","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Boa tarde","time":"22/01/2026 13:44:59"},{"role":"client","text":"Hoje nao tive condições de finalizar ainda","time":"22/01/2026 13:45:13"},{"role":"client","text":"Tentarei fazer isso hoje a tarde","time":"22/01/2026 13:45:20"},{"role":"client","text":"Mas, eu vi o contrato","time":"22/01/2026 13:46:15"},{"role":"client","text":"E já aceitei","time":"22/01/2026 13:46:21"},{"role":"client","text":"Mas, não consegui, pelo celular, emitir o boleto","time":"22/01/2026 13:46:38"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/697254f5d7f765334f0987d1)","time":"22/01/2026 13:48:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69725719dedf7daa1902f919)","time":"22/01/2026 13:58:02"},{"role":"client","text":"Consegui","time":"22/01/2026 13:58:03"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/6972575eef9b84ff3a02a935)","time":"22/01/2026 13:59:10"},{"role":"agent","text":"*Thayanne Sales:* Que maravilha, seja muito bem-vindo a Faculdade Internacional Cidade Viva.","time":"22/01/2026 14:00:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Agora é só aguardar o inicio das aulas em 02/02, o acesso será enviado para o seu e-mail. ","time":"22/01/2026 14:01:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"22/01/2026 14:01:43","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ok","time":"22/01/2026 14:06:19"},{"role":"client","text":"Obrigado","time":"22/01/2026 14:06:31"},{"role":"client","text":"Eu já tenho acesso ao Moodle pois já havia comprado cursos livres e uma pós. Creio que o login será o mesmo, ne isso?","time":"22/01/2026 14:07:17"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"22/01/2026 14:07:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Sim, será liberado as aulas no dia 02/02 lá","time":"22/01/2026 14:07:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigado. Um excelente dia pra vc tb","time":"22/01/2026 14:08:32"},{"role":"agent","text":"*Thayanne Sales:* Agradeço. Até mais!","time":"22/01/2026 14:08:54","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nDeoclécio Vieira de Melo Neto, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"22/01/2026 14:08:56"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"25/01/2026 14:06:33"},{"role":"client","text":"Sua sessão expirou!","time":"25/01/2026 14:08:35"}]$tag$, $tag$2026-01-21 12:01:26+00$tag$, FALSE, FALSE, 8.2,