INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b935b10b-47a9-4f43-83d8-71a60f254ee0$tag$, $tag$2026012100160$tag$, $tag$Dani Landal (5541987851776)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"21/01/2026 16:01:21"},{"role":"client","text":"🌟 Boa tarde Dani Landal! Que alegria ter você aqui com a gente! 🙌","time":"21/01/2026 16:01:22"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"21/01/2026 16:01:26"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"21/01/2026 16:01:30"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"21/01/2026 16:01:34"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"21/01/2026 16:01:40"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"21/01/2026 16:01:46"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"21/01/2026 16: