INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1806357f-588d-4a90-bb33-d6493fdd4812$tag$, $tag$2026012200027$tag$, $tag$LM (5583998939911)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"22/01/2026 09:27:29"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"22/01/2026 09:27:30"},{"role":"client","text":"Gostaria de informações de valores e tempo de formação dos cursos de vocês. Também gostaria de saber se vocês tem um Polo presencial do curso de Teologia","time":"22/01/2026 09:28:17"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"22/01/2026 09:30:22"},{"role":"agent","text":"*Karina Pimentel:*   \n *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"22/01/2026 09:31:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"22/01/2026 09:32:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ja sou formado em Direito pela Unipê e meu interesse é no curso de Teologia","time":"22/01/2026 10:59:29"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"22/01/2026 11:02:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar informações!","time":"22/01/2026 11:02:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*   A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"22/01/2026 11:02:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 20%* na pontualidade durante toda graduação, que fica apenas R$ 439,64.  *Usando o cupom de desconto: BOLSA20*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.637,88).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 439,64 = R$ 2.637,88\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 527,57 = R$ 2.637,88\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 659,47 = R$ 2.637,88\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"22/01/2026 11:03:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Entendi","time":"22/01/2026 11:08:27"},{"role":"client","text":"Onde fica localizado o Polo presencial das aulas de Teologia?","time":"22/01/2026 11:08:47"},{"role":"client","text":"Quais são os valores do curso no formato EAD?","time":"22/01/2026 11:10:23"},{"role":"agent","text":"*Karina Pimentel:* Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.","time":"22/01/2026 11:11:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"22/01/2026 11:11:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"22/01/2026 11:12:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 16:34:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oi","time":"23/01/2026 16:41:00"},{"role":"client","text":"Gostaria de conhecer a faculdade pessoalmente","time":"23/01/2026 16:41:37"},{"role":"client","text":"Tem alguma possibilidade de bolsa em Teologia?","time":"23/01/2026 16:41:58"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6973cf5d3959368e1705f23c)","time":"23/01/2026 16:43:25"},{"role":"agent","text":"*Karina Pimentel:* Claro!","time":"23/01/2026 17:39:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Até 19  hrs o atendimento da Secretaria da Faculdade!","time":"23/01/2026 17:42:18","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Pois as aulas retornaram no dia 02/02","time":"23/01/2026 17:42:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Após o inicio das aulas, fica até as 20:30 hrs","time":"23/01/2026 17:43:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ta bem","time":"23/01/2026 19:12:06"},{"role":"client","text":"Funciona aos sábados?","time":"23/01/2026 19:12:11"},{"role":"client","text":"Oii","time":"24/01/2026 11:07:17"},{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"26/01/2026 16:46:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Opa","time":"26/01/2026 17:40:36"},{"role":"client","text":"Ate que horas ta aberta a faculdade hj?","time":"26/01/2026 17:40:42"},{"role":"client","text":"Gostaria de conhecer","time":"26/01/2026 17:40:46"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"26/01/2026 17:53:34","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Até as 19 hrs","time":"26/01/2026 17:53:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ta bem!","time":"26/01/2026 18:15:11"},{"role":"client","text":"Essa semana passo por aí","time":"26/01/2026 18:15:20"},{"role":"client","text":"Qual dia começam as aulas de Teologia?","time":"26/01/2026 18:15:29"},{"role":"agent","text":"*Karina Pimentel:* 02/02 - Teologia Ead","time":"26/01/2026 18:18:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 05/02 -  Teologia presencial","time":"26/01/2026 18:18:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:36:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nLM, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"27/01/2026 18:23:26"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"29/01/2026 18:13:37"},{"role":"client","text":"Sua sessão expirou!","time":"29/01/2026 18:15:38"}]$tag$, $tag$2026-01-22 09:27:29+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 20, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$623d063e-730f-47c0-bc29-ad1dedae7de3$tag$, $tag$2026012200028$tag$, $tag$Marlon Reguelin (5541984123718)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"22/01/2026 09:29:29"},{"role":"client","text":"🌟 Bom dia Marlon Reguelin! Que alegria ter você aqui com a gente! 🙌","time":"22/01/2026 09:29:30"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"22/01/2026 09:29:34"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"22/01/2026 09:29:38"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"22/01/2026 09:29:42"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"22/01/2026 09:29:48"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"22/01/2026 09:29:54"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"22/01/2026 09:29:55"},{"role":"client","text":"Sim, concordo","time":"22/01/2026 09:31:09"},{"role":"client","text":"✅ Obrigado, Marlon Reguelin! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"22/01/2026 09:31:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"22/01/2026 09:31:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"22/01/2026 09:31:31"},{"role":"client","text":"Olá! Marlon Reguelin!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"22/01/2026 09:31:32"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"22/01/2026 09:31:36"},{"role":"client","text":"Saber sobre os cursos","time":"22/01/2026 09:33:23"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"22/01/2026 09:33:27"},{"role":"client","text":"Pós-Graduação","time":"22/01/2026 09:33:37"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"22/01/2026 09:33:41"},{"role":"client","text":"Ciência Política","time":"22/01/2026 09:33:57"},{"role":"client","text":"Quer compreender os fundamentos políticos a partir de uma cosmovisão cristã?\n 📘 Curso voltado para quem atua ou deseja atuar em política, gestão pública ou liderança institucional\n 📅 Início em agosto\n 💻 Estudo online e contextualizado\n","time":"22/01/2026 09:33:58"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"22/01/2026 09:34:01"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"22/01/2026 09:34:12"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"22/01/2026 09:34:13"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"22/01/2026 09:34:59"},{"role":"agent","text":"*Karina Pimentel:* *Pós-Graduação em Ciência Política e Atuação Pública*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 480 h.\n\nDISCIPLINAS\nContamos com um total de 11 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"22/01/2026 09:35:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   O valor de investimento na Pós-graduação em Ciência Política está em 16 mensalidades de R$ *487,00*.  Estamos com condição especiais com 20% e as mensalidades estão saindo por R$ 389,60.","time":"22/01/2026 09:37:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 16:27:32","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"25/01/2026 09:33:00"},{"role":"client","text":"Sua sessão expirou!","time":"25/01/2026 09:35:01"}]$tag$, $tag$2026-01-22 09:29:29+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, 