INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$af34f09b-825a-4480-96c7-cb537ec0093f$tag$, $tag$2026012200076$tag$, $tag$Felipe (5519997975802)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"22/01/2026 13:12:57"},{"role":"client","text":"🌟 Boa tarde Felipe! Que alegria ter você aqui com a gente! 🙌","time":"22/01/2026 13:12:58"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"22/01/2026 13:13:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"22/01/2026 13:13:05"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"22/01/2026 13:13:09"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"22/01/2026 13:13:16"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"22/01/2026 13:13:22"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"22/01/2026 13:13:23"},{"role":"client","text":"Sim, concordo","time":"22/01/2026 13:13:50"},{"role":"client","text":"✅ Obrigado, Felipe! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"22/01/2026 13:13:51"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"22/01/2026 13:13:55"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"22/01/2026 13:15:05"},{"role":"client","text":"Olá! Felipe!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"22/01/2026 13:15:06"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"22/01/2026 13:15:10"},{"role":"client","text":"Saber sobre os cursos","time":"22/01/2026 13:15:36"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"22/01/2026 13:15:40"},{"role":"client","text":"Graduação","time":"22/01/2026 13:16:28"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"22/01/2026 13:16:32"},{"role":"client","text":"Teologia (Presencial)","time":"22/01/2026 13:17:08"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"22/01/2026 13:17:09"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"22/01/2026 13:17:14"},{"role":"client","text":"Onde é a faculdade?","time":"22/01/2026 13:17:14"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"22/01/2026 13:17:15"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"22/01/2026 13:20:58"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"22/01/2026 13:21:00"},{"role":"client","text":".","time":"22/01/2026 13:21:14"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"22/01/2026 13:21:27"},{"role":"agent","text":"*Karina Pimentel:* Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.","time":"22/01/2026 13:21:43","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Teologia (EAD)","time":"22/01/2026 14:11:42"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"22/01/2026 14:23:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"22/01/2026 14:23:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia\nQual é a grade","time":"23/01/2026 08:44:46"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"23/01/2026 09:18:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"23/01/2026 09:18:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Sobre as provas?","time":"23/01/2026 13:37:23"},{"role":"agent","text":"*Karina Pimentel:* No fim de cada modulo, o seu tutor vai lhe orientar!","time":"23/01/2026 16:09:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Será tudo ead.","time":"23/01/2026 16:09:28","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"26/01/2026 13:35:25"},{"role":"client","text":"Sua sessão expirou!","time":"26/01/2026 13:37:26"}]$tag$, $tag$2026-01-22 13:12:57+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.times